// ============================================================
// Airport Monitor — Parseo FAA XML + Generación mensaje WhatsApp
// ============================================================

const xml = $input.first().json.data || $input.first().json.body || $input.first().json || '';

// Aeropuertos a monitorear
const WATCHED = ['MIA', 'JFK', 'EWR', 'EZE', 'GCM'];

// Mis vuelos
const MY_FLIGHTS = [
  { date: '29 Mar', flight: 'AA 900',   from: 'EZE', to: 'MIA', time: '20:30' },
  { date: '31 Mar', flight: 'AA 956',   from: 'MIA', to: 'GCM', time: '12:55' },
  { date: '05 Abr', flight: 'B6 766',   from: 'GCM', to: 'JFK', time: '15:40' },
  { date: '11 Abr', flight: 'DL 1514',  from: 'JFK', to: 'MIA', time: '11:10' },
  { date: '11 Abr', flight: 'AA 931',   from: 'MIA', to: 'EZE', time: '21:15' },
];

// Helper: extraer texto entre tags XML
function getTag(xml, tag) {
  const match = xml.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`, 'i'));
  return match ? match[1].trim() : null;
}

function getAllBlocks(xml, tag) {
  const blocks = [];
  const regex = new RegExp(`<${tag}[^>]*>[\\s\\S]*?<\/${tag}>`, 'gi');
  let match;
  while ((match = regex.exec(xml)) !== null) {
    blocks.push(match[0]);
  }
  return blocks;
}

const problems = {};

// Delays normales
getAllBlocks(xml, 'Delay').forEach(block => {
  const arpt = getTag(block, 'ARPT');
  if (!arpt) return;
  const depMin = parseInt(getTag(block, 'Min') || '0');
  const depMax = parseInt(getTag(block, 'Max') || '0');
  const reason = getTag(block, 'Reason') || 'Unknown';
  const trend  = getTag(block, 'Trend')  || '';
  const avg    = (depMin + depMax) / 2;
  problems[arpt] = {
    type:     'delay',
    severity: avg <= 15 ? 'minor' : avg <= 45 ? 'moderate' : 'severe',
    reason, min: depMin, max: depMax, trend
  };
});

// Ground Stops
getAllBlocks(xml, 'GroundStop').forEach(block => {
  const arpt = getTag(block, 'ARPT');
  if (!arpt) return;
  problems[arpt] = {
    type: 'ground_stop', severity: 'critical',
    reason:  getTag(block, 'Reason')  || 'Unknown',
    endTime: getTag(block, 'EndTime') || 'indefinido'
  };
});

// Ground Delays
getAllBlocks(xml, 'GroundDelay').forEach(block => {
  const arpt = getTag(block, 'ARPT');
  if (!arpt) return;
  problems[arpt] = {
    type: 'ground_delay', severity: 'critical',
    reason: getTag(block, 'Reason') || 'Unknown',
    avg:    getTag(block, 'Avg')    || '?',
    max:    getTag(block, 'Max')    || '?'
  };
});

// Closures
getAllBlocks(xml, 'AirportClosure').forEach(block => {
  const arpt = getTag(block, 'ARPT');
  if (!arpt) return;
  problems[arpt] = {
    type: 'closure', severity: 'critical',
    reason: getTag(block, 'Reason') || 'Unknown'
  };
});

// Generar mensaje WhatsApp
const now = new Date().toLocaleString('es-AR', {
  timeZone: 'America/Argentina/Buenos_Aires',
  day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit'
});

let msg = `✈️ *Airport Monitor — ${now} (ARG)*\n\n`;

const watchedProblems = WATCHED.filter(a => problems[a]);
const watchedOk       = WATCHED.filter(a => !problems[a]);

if (watchedProblems.length === 0) {
  msg += `✅ *Todo normal*\nSin demoras en tus aeropuertos\n\n`;
} else {
  msg += `⚠️ *${watchedProblems.length} aeropuerto(s) con problemas:*\n\n`;
  watchedProblems.forEach(iata => {
    const p = problems[iata];
    const emoji = p.type === 'closure'    ? '⛔'
                : p.type === 'ground_stop' ? '🛑'
                : p.severity === 'critical'  ? '🔴'
                : p.severity === 'severe'    ? '🔴'
                : p.severity === 'moderate'  ? '🟠' : '🟡';
    msg += `${emoji} *${iata}*\n`;
    if (p.type === 'delay') {
      msg += `   Demora: ${p.min}-${p.max} min\n`;
      msg += `   Causa: ${p.reason}\n`;
      if (p.trend) msg += `   Tendencia: ${p.trend}\n`;
    } else if (p.type === 'ground_stop') {
      msg += `   🛑 Ground Stop hasta ${p.endTime}\n`;
      msg += `   Causa: ${p.reason}\n`;
    } else if (p.type === 'ground_delay') {
      msg += `   🔴 Ground Delay: avg ${p.avg} min\n`;
      msg += `   Causa: ${p.reason}\n`;
    } else if (p.type === 'closure') {
      msg += `   ⛔ CERRADO — ${p.reason}\n`;
    }
    msg += '\n';
  });
}

if (watchedOk.length > 0) {
  msg += `✅ *OK:* ${watchedOk.join(' · ')}\n\n`;
}

// Estado de mis vuelos
msg += `─────────────────\n🗓️ *Mis vuelos:*\n\n`;
MY_FLIGHTS.forEach(f => {
  const originStatus = problems[f.from];
  const emoji = !originStatus            ? '🟢'
              : originStatus.type === 'closure'     ? '⛔'
              : originStatus.severity === 'critical' ? '🔴'
              : originStatus.severity === 'severe'   ? '🔴'
              : originStatus.severity === 'moderate' ? '🟠' : '🟡';
  msg += `${emoji} ${f.date} · ${f.flight}\n`;
  msg += `   ${f.from} → ${f.to} · Sale ${f.time}\n`;
  if (originStatus) {
    if (originStatus.type === 'delay') {
      msg += `   ⚠️ Demora en ${f.from}: ${originStatus.min}-${originStatus.max} min\n`;
    } else if (originStatus.type === 'ground_stop') {
      msg += `   🛑 Ground Stop en ${f.from} hasta ${originStatus.endTime}\n`;
    } else if (originStatus.type === 'ground_delay') {
      msg += `   🔴 Ground Delay en ${f.from}: avg ${originStatus.avg} min\n`;
    } else if (originStatus.type === 'closure') {
      msg += `   ⛔ ${f.from} CERRADO — ${originStatus.reason}\n`;
    }
  }
  msg += '\n';
});

msg += `_Fuente: FAA · próxima actualización en 12hs_`;

return [{ json: { message: msg, hasProblems: watchedProblems.length > 0 } }];
